Patching the snake widget directly from the loaded transient state.
_____javascript
const widget = space.chat.transient.get("snake-game");
if (!widget) throw new Error('snake-game widget not found in transient');

const text = widget.text ?? widget.content ?? widget.source ?? widget.code ?? widget.value ?? '';
const original = String(text);

const needle = /(\b(?:move|advance|step|updatePosition|updateSnake|moveSnake|tick|gameLoop|draw|render)\b[\s\S]{0,1200}?)(\n|;|\})/i;
const candidate = original;

let edited = candidate;

if (/requestAnimationFrame|interpolate|lerp|animation|transition/.test(original)) {
  return 'already-animated';
}

const insertions = [];
if (/setInterval\s*\(/.test(original)) {
  insertions.push(`\n// smoother movement interpolation
const SNAKE_ANIM_MS = 110;
let snakeRenderBody = window.__snakeRenderBody || null;
window.__snakeRenderBody = snakeRenderBody;
`);
}

edited = edited.replace(
  /(\bfunction\s+\w*render\w*[\s\S]{0,2000}?)(return\b|}\s*\/\/|}\s*$)/i,
  (m) => m
);

if (/const\s+CELL_SIZE\s*=/.test(original) && !/const\s+SNAKE_ANIM_MS\s*=/.test(original)) {
  edited = edited.replace(
    /(const\s+CELL_SIZE\s*=\s*[^;\n]+;)/,
    `$1\nconst SNAKE_ANIM_MS = 110;`
  );
}

if (!/function\s+drawSnake/i.test(original) && /draw/i.test(original)) {
  edited = edited.replace(
    /(\bfunction\s+draw\w*\s*\([\s\S]*?\{)/i,
    `$1\n  const now = performance.now();`
  );
}

if (!/lerp|interpolate/.test(edited)) {
  const helper = `
function lerp(a, b, t) { return a + (b - a) * t; }
function easeOutCubic(t) { return 1 - Math.pow(1 - t, 3); }
`;
  edited = helper + edited;
}

edited = edited.replace(
  /(\bconst\s+headX\s*=\s*[^;\n]+;\s*\n\s*const\s+headY\s*=\s*[^;\n]+;)/,
  `$1\n  const animT = easeOutCubic(Math.min(1, (performance.now() - (snakeMoveStartTime ?? 0)) / SNAKE_ANIM_MS));`
);

if (edited === original) {
  throw new Error('No safe edit point found for snake widget source.');
}

return await space.current.patchWidget("snake-game", { edits: [{ find: original, replace: edited }] });

