_____javascript
const widget = await space.current.readWidget("snake-game");
const src = widget?.content ?? widget?.code ?? widget?.text ?? widget;
let text = typeof src === "string" ? src : JSON.stringify(src, null, 2);

const replacements = [
  [/background\s*:\s*[^;]+;/g, 'background: linear-gradient(180deg, #7fbf5b 0%, #5f9f46 100%);'],
  [/background-color\s*:\s*[^;]+;/g, 'background-color: #7fbf5b;'],
  [/color\s*:\s*[^;]+;/g, 'color: #173b10;'],
  [/box-shadow\s*:\s*[^;]+;/g, 'box-shadow: inset 0 0 0 2px rgba(23,59,16,0.18);'],
  [/font-family\s*:\s*[^;]+;/g, 'font-family: "Courier New", Courier, monospace;'],
];

for (const [re, rep] of replacements) text = text.replace(re, rep);

if (!/nokia|lcd|monochrome|retro/i.test(text)) {
  text = text.replace(
    /(<style[^>]*>)/i,
    `$1\n  .snake-game, .snake-game * {\n    font-family: "Courier New", Courier, monospace;\n    text-shadow: 0 0 1px rgba(23,59,16,0.2);\n  }\n  .snake-game {\n    background: linear-gradient(180deg, #8bcf66 0%, #6aa84f 100%);\n    color: #173b10;\n    box-shadow: inset 0 0 0 2px rgba(23,59,16,0.18);\n  }\n  .snake-game canvas {\n    image-rendering: pixelated;\n    background: rgba(127,191,91,0.95);\n    border: 2px solid rgba(23,59,16,0.28);\n  }\n`
  );
}

return await space.current.patchWidget("snake-game", { edits: [{ type: "replaceAll", text }] })

